function ScrollColorTransition() {
  const contactRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      if (contactRef.current) {
        const contactPosition = contactRef.current.getBoundingClientRect().top;
        const windowHeight = window.innerHeight;
        const scrollProgress = Math.min(1 - (contactPosition / windowHeight), 1);

        const startColor = [0, 0, 0]; // Black
        const endColor = [31, 41, 55]; // #1f2937 in RGB

        const interpolatedColor = startColor.map((start, index) => {
          const diff = endColor[index] - start;
          return Math.round(start + diff * scrollProgress);
        });

        document.body.style.backgroundColor = `rgb(${interpolatedColor.join(',')})`;
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return <div ref={contactRef} style={{ position: 'absolute', top: '400vh' }} />;
}


